class Solution:
    def removeNodes(self, head):
        def reverse(node):
            prev = None
            while node:
                nxt = node.next
                node.next = prev
                prev = node
                node = nxt
            return prev

        rev = reverse(head)
        best = rev.val
        current = rev
        while current.next:
            if current.next.val < best:
                current.next = current.next.next
            else:
                current = current.next
                best = current.val
        return reverse(rev)

