var removeNodes = function(head) {
    function reverse(node) {
        let prev = null;
        while (node) {
            const nxt = node.next;
            node.next = prev;
            prev = node;
            node = nxt;
        }
        return prev;
    }

    const rev = reverse(head);
    let best = rev.val;
    let current = rev;
    while (current.next) {
        if (current.next.val < best) {
            current.next = current.next.next;
        } else {
            current = current.next;
            best = current.val;
        }
    }
    return reverse(rev);
};
